/**
 * DonkeyCode — MV3 service worker: script sync, injection, sessions, alarms.
 */

const LOG_PREFIX = "[DonkeyCode:background]";

const DEFAULT_SCRIPT_SOURCE_URL =
  "https://api.github.com/repos/MikeBane57/Wolf2.0/contents/?ref=main";

/**
 * Optional baked GitHub defaults: generated by `npm run build` → DonkeyCode/baked-config.js
 * (gitignored). If missing, empty defaults below apply.
 */
try {
  importScripts("baked-config.js");
} catch (e) {
  self.BAKED_GITHUB_DEFAULTS = {
    token: "",
    owner: "",
    repo: "",
    branch: "main",
    path: "sessions/donkeycode-sessions.json",
  };
}

const SESSION_JSON_FILENAME = "donkeycode-sessions.json";
/** Per session-folder script toggles + future per-script options (same folder path as sessions). */
const SCRIPT_PREFS_JSON_FILENAME = "donkeycode-script-prefs.json";

function joinGithubRepoPath(rootDir, ...segments) {
  const parts = [];
  const r = (rootDir || "").trim().replace(/^\/+|\/+$/g, "").replace(/\\/g, "/");
  if (r) parts.push(r);
  for (const seg of segments) {
    const s = (seg || "").trim().replace(/^\/+|\/+$/g, "").replace(/\\/g, "/");
    if (s) parts.push(s);
  }
  return parts.join("/");
}

function defaultSessionFilePathForRoot(sessionsRoot) {
  return joinGithubRepoPath(sessionsRoot, SESSION_JSON_FILENAME);
}

/** User may enter a directory (e.g. sessions) or legacy path ending in .json */
function normalizeUserSessionsRootInput(input) {
  const t = (input || "").trim().replace(/^\/+/, "").replace(/\/+$/g, "");
  if (!t) return "sessions";
  if (/\.json$/i.test(t)) {
    const i = t.lastIndexOf("/");
    return i === -1 ? "" : t.slice(0, i);
  }
  return t;
}

function deriveSessionsRootFromLegacyPath(raw) {
  const path = (raw || "").trim().replace(/^\/+/, "");
  if (!path) return "sessions";
  if (/\.json$/i.test(path)) {
    const i = path.lastIndexOf("/");
    return i === -1 ? "" : path.slice(0, i);
  }
  return path.replace(/\/+$/, "");
}

const STORAGE = {
  SCRIPT_SOURCE: "donkeycode_script_source_url",
  EXTRA_URLS: "donkeycode_extra_script_urls",
  SCRIPTS: "donkeycode_scripts",
  SESSIONS: "donkeycode_sessions",
  SESSION_FOLDERS_V2: "donkeycode_session_folders_v2",
  CURRENT_SESSION_FOLDER: "donkeycode_current_session_folder",
  /** Legacy: flat sessions in sync before folder model */
  SESSIONS_LEGACY_MIGRATED: "donkeycode_sessions_legacy_migrated",
  /** v3: session blobs moved from sync (8KB/item limit) to chrome.storage.local */
  SESSION_STORAGE_MIGRATED: "donkeycode_sessions_storage_migrated_v3",
  LAST_FETCH: "donkeycode_last_script_fetch_ms",
  PENDING_RESTORE: "donkeycode_pending_restore_session",
  /** Window ids for Login First flow (close on Continue). */
  LOGIN_FLOW_WINDOW_IDS: "donkeycode_login_flow_window_ids",
  /** Tab id of the tab that started Login First (close on Continue if not a login page). */
  LOGIN_FLOW_OPENER_TAB_ID: "donkeycode_login_flow_opener_tab_id",
  SETUP_DISMISSED: "donkeycode_setup_banner_dismissed",
  PENDING_FIRST_POPUP_REFRESH: "donkeycode_pending_first_popup_refresh",
  GITHUB_PAT: "donkeycode_github_pat",
  GITHUB_OWNER: "donkeycode_github_owner",
  GITHUB_REPO: "donkeycode_github_repo",
  GITHUB_BRANCH: "donkeycode_github_branch",
  GITHUB_PATH: "donkeycode_github_path",
  GITHUB_SESSIONS_ROOT: "donkeycode_github_sessions_root",
  GITHUB_SYNC_LAST_ERROR: "donkeycode_github_sync_last_error",
  GITHUB_SYNC_LAST_OK: "donkeycode_github_sync_last_ok",
  /** Set on first install; cleared after popup runs one GitHub session pull when configured */
  PENDING_INITIAL_SESSION_PULL: "donkeycode_pending_initial_session_pull",
  /** Cleared after popup runs one GitHub folder discover when configured */
  PENDING_INITIAL_FOLDER_DISCOVER: "donkeycode_pending_initial_folder_discover",
  /** Save/restore per-tab zoom in session layouts (default: on). */
  SESSION_SAVE_ZOOM_PER_TAB: "donkeycode_session_save_zoom_per_tab",
};

/** Default URLs opened before restoring a session (user signs in, then continues). */
const LOGIN_WINDOW_URLS = [
  "https://opssuitemain.swacorp.com/",
  "https://www.swalife.com/",
];

const ALARM_DAILY = "donkeycode_daily_script_refresh";

/** Optional broad host patterns (must match manifest optional_host_permissions). */
const OPTIONAL_ORIGIN_PATTERNS = ["http://*/*", "https://*/*"];

const BRIDGE_CS_ID = "donkeycode-bridge";

/** @type {Map<number, Set<string>>} */
const tabInjectedScripts = new Map();

async function hasOriginAccessForUrl(pageUrl) {
  try {
    const u = new URL(pageUrl);
    if (u.protocol !== "http:" && u.protocol !== "https:") return false;
    return await hasOptionalHostAccess();
  } catch (e) {
    return false;
  }
}

async function hasOptionalHostAccess() {
  return chrome.permissions.contains({ origins: OPTIONAL_ORIGIN_PATTERNS });
}

async function registerBridgeContentScripts() {
  try {
    await chrome.scripting.unregisterContentScripts({ ids: [BRIDGE_CS_ID] });
  } catch (e) {
    /* ignore */
  }
  await chrome.scripting.registerContentScripts([
    {
      id: BRIDGE_CS_ID,
      matches: ["http://*/*", "https://*/*"],
      js: ["bridge.js"],
      runAt: "document_start",
      allFrames: false,
    },
  ]);
  log("registered bridge content script");
}

async function unregisterBridgeContentScripts() {
  try {
    await chrome.scripting.unregisterContentScripts({ ids: [BRIDGE_CS_ID] });
    log("unregistered bridge content script");
  } catch (e) {
    /* ignore */
  }
}

async function ensureHostAccessAndBridge() {
  const ok = await hasOptionalHostAccess();
  if (!ok) {
    log("optional http(s) host access not granted — grant in extension settings to run scripts");
    await unregisterBridgeContentScripts();
    return false;
  }
  try {
    await registerBridgeContentScripts();
  } catch (e) {
    logError("registerBridgeContentScripts failed", e);
  }
  applyPerTabZoomScopeToOpenHttpTabs().catch(() => {});
  return true;
}

if (chrome.permissions && chrome.permissions.onRemoved) {
  chrome.permissions.onRemoved.addListener((details) => {
    if (details.origins && details.origins.length) {
      hasOptionalHostAccess().then((still) => {
        if (!still) unregisterBridgeContentScripts();
        updateInstallBadge().catch(() => {});
      });
    }
  });
}

async function updateInstallBadge() {
  try {
    const dismissed = await chrome.storage.local.get(STORAGE.SETUP_DISMISSED);
    if (dismissed[STORAGE.SETUP_DISMISSED]) {
      await chrome.action.setBadgeText({ text: "" });
      return;
    }
    const hasHost = await hasOptionalHostAccess();
    const scripts = await getStoredScripts();
    const needsPerm = !hasHost;
    const needsScripts = scripts.length === 0;
    if (needsPerm || needsScripts) {
      await chrome.action.setBadgeText({ text: "!" });
      await chrome.action.setBadgeBackgroundColor({ color: needsPerm ? "#C62828" : "#F57C00" });
    } else {
      await chrome.action.setBadgeText({ text: "" });
    }
  } catch (e) {
    logWarn("updateInstallBadge", e);
  }
}

function log(...args) {
  console.log(LOG_PREFIX, ...args);
}

function logWarn(...args) {
  console.warn(LOG_PREFIX, ...args);
}

function logError(...args) {
  console.error(LOG_PREFIX, ...args);
}

/**
 * One-time: derive sessions root from stored GITHUB_PATH and/or baked path.
 */
async function migrateGithubSessionsRootIfNeeded() {
  const d = await chrome.storage.local.get([
    STORAGE.GITHUB_SESSIONS_ROOT,
    STORAGE.GITHUB_PATH,
  ]);
  if (
    Object.prototype.hasOwnProperty.call(d, STORAGE.GITHUB_SESSIONS_ROOT) &&
    d[STORAGE.GITHUB_SESSIONS_ROOT] !== undefined &&
    d[STORAGE.GITHUB_SESSIONS_ROOT] !== null
  ) {
    return;
  }
  const baked = self.BAKED_GITHUB_DEFAULTS || {};
  const rawFromStorage = (d[STORAGE.GITHUB_PATH] || "").trim();
  const rawFromBaked = String(baked.path || "").trim();
  const raw = rawFromStorage || rawFromBaked;
  const root = deriveSessionsRootFromLegacyPath(raw);
  await chrome.storage.local.set({ [STORAGE.GITHUB_SESSIONS_ROOT]: root });
  log("GitHub sessions root migrated:", root, "from", raw || "(default)");
}

function scriptIdFromUrl(url) {
  let h = 2166136261;
  for (let i = 0; i < url.length; i++) {
    h ^= url.charCodeAt(i);
    h = Math.imul(h, 16777619);
  }
  return "dc_" + (h >>> 0).toString(16);
}

/**
 * Parse ==UserScript== metadata and body.
 * @param {string} fullText
 */
function parseUserScript(fullText) {
  const blockMatch = fullText.match(
    /\/\/\s*==UserScript==([\s\S]*?)\/\/\s*==\/UserScript==/i
  );
  const metaText = blockMatch ? blockMatch[1] : "";
  const body = blockMatch
    ? fullText.slice(blockMatch.index + blockMatch[0].length).replace(/^\s*/, "")
    : fullText;

  const matches = [];
  const excludes = [];
  const grants = [];
  const connects = [];
  let userScriptName = "";
  let userScriptVersion = "";
  let userScriptDescription = "";
  /** @type {Record<string, { type?: string, default?: unknown, label?: string }>} */
  let donkeycodePrefSchema = {};
  const lines = metaText.split(/\r?\n/);
  for (const line of lines) {
    const m = line.match(/^\s*\/\/\s*@(\S+)\s+(.*)$/);
    if (!m) continue;
    const key = m[1].toLowerCase();
    const val = (m[2] || "").trim();
    if (key === "match") matches.push(val);
    else if (key === "exclude") excludes.push(val);
    else if (key === "grant") grants.push(val);
    else if (key === "connect") connects.push(val);
    else if (key === "name" && val) userScriptName = val;
    else if (key === "version" && val) userScriptVersion = val;
    else if (key === "description" && val) userScriptDescription = val;
    else if (key === "donkeycode-pref" && val) {
      try {
        const parsed = JSON.parse(val);
        if (parsed && typeof parsed === "object" && !Array.isArray(parsed)) {
          donkeycodePrefSchema = Object.assign(donkeycodePrefSchema, parsed);
        }
      } catch (e) {
        logWarn("@donkeycode-pref JSON parse failed", val.slice(0, 80));
      }
    }
  }

  if (matches.length === 0) matches.push("*://*/*");

  return {
    matches,
    excludes,
    grants,
    connects,
    userScriptName,
    userScriptVersion,
    userScriptDescription,
    donkeycodePrefSchema,
    body,
  };
}

function prefDefaultsFromSchema(schema) {
  const out = {};
  if (!schema || typeof schema !== "object" || Array.isArray(schema)) return out;
  for (const [k, v] of Object.entries(schema)) {
    if (v && typeof v === "object" && !Array.isArray(v) && Object.prototype.hasOwnProperty.call(v, "default")) {
      out[k] = v.default;
    }
  }
  return out;
}

function mergeUserPrefsWithSchemaDefaults(stored, schema) {
  const defs = prefDefaultsFromSchema(schema);
  const base = Object.assign({}, defs);
  if (!stored || typeof stored !== "object" || Array.isArray(stored)) return base;
  return Object.assign(base, stored);
}

/**
 * @param {string} hostname
 * @param {string} pattern e.g. example.com or *.example.com
 */
function hostMatchesConnect(hostname, pattern) {
  const p = (pattern || "").trim().toLowerCase();
  const h = (hostname || "").toLowerCase();
  if (!p) return false;
  if (p.startsWith("*.")) {
    const suf = p.slice(2);
    return h === suf || h.endsWith("." + suf);
  }
  return h === p;
}

function urlAllowedByConnects(pageUrl, connects) {
  if (!connects || connects.length === 0) return true;
  if (connects.some((c) => String(c).trim() === "*")) return true;
  let u;
  try {
    u = new URL(pageUrl);
  } catch (e) {
    return false;
  }
  if (u.protocol !== "http:" && u.protocol !== "https:") return false;
  for (const c of connects) {
    if (hostMatchesConnect(u.hostname, c.trim())) return true;
  }
  return false;
}

/**
 * Tampermonkey-style @match against a page URL (simplified).
 * @param {string} pattern e.g. *://*.example.com/foo*
 * @param {string} pageUrl
 */
function urlMatchesPattern(pattern, pageUrl) {
  try {
    const u = new URL(pageUrl);
    if (u.protocol === "chrome-extension:" || u.protocol === "chrome:") return false;

    const normalized = pattern.trim();
    const parts = normalized.match(/^(\*|https?|file|ftp):\/\/([^/]+)(\/.*)$/i);
    if (!parts) return false;

    const schemePat = parts[1].toLowerCase();
    const hostPat = parts[2];
    const pathPat = parts[3] || "/";

    const scheme = (u.protocol || "").replace(":", "").toLowerCase();
    if (schemePat !== "*" && schemePat !== scheme) return false;

    if (!hostMatches(hostPat, u.hostname)) return false;
    if (!pathMatches(pathPat, u.pathname + u.search)) return false;
    return true;
  } catch (e) {
    logWarn("match parse error", pattern, e);
    return false;
  }
}

function hostMatches(pat, host) {
  if (pat === "*") return true;
  if (pat.startsWith("*.")) {
    const rest = pat.slice(2);
    return host === rest || host.endsWith("." + rest);
  }
  if (pat.includes("*")) {
    const re = new RegExp(
      "^" +
        pat.replace(/[.+?^${}()|[\]\\]/g, "\\$&").replace(/\*/g, ".*") +
        "$",
      "i"
    );
    return re.test(host);
  }
  return host.toLowerCase() === pat.toLowerCase();
}

function pathMatches(pat, pathAndQuery) {
  const re = new RegExp(
    "^" + pat.replace(/[.+?^${}()|[\]\\]/g, "\\$&").replace(/\*/g, ".*") + "$",
    "i"
  );
  return re.test(pathAndQuery);
}

function scriptMatchesUrl(script, pageUrl) {
  for (const ex of script.excludes || []) {
    if (urlMatchesPattern(ex, pageUrl)) {
      log("URL skipped (exclude)", { id: script.id, pageUrl, ex });
      return false;
    }
  }
  for (const m of script.matches || []) {
    if (urlMatchesPattern(m, pageUrl)) {
      log("URL matched", { id: script.id, pageUrl, match: m });
      return true;
    }
  }
  log("URL skipped (no @match)", { id: script.id, pageUrl });
  return false;
}

/**
 * Injected into MAIN world — runs user code and registers cleanup.
 * Passes Tampermonkey-style GM_xmlhttpRequest when @grant requests it (via
 * new Function argument so each script keeps the correct script id for @connect).
 * Must be self-contained (serialized).
 * @param {{ id: string, code: string, grants?: string[], connects?: string[], userPrefs?: object, donkeycodePrefSchema?: object }} payload
 */
function donkeycodeInjectMain(payload) {
  const scriptId = payload.id;
  const code = payload.code;
  const grants = payload.grants || [];
  const connects = payload.connects || [];
  const userPrefs = payload.userPrefs && typeof payload.userPrefs === "object" && !Array.isArray(payload.userPrefs)
    ? payload.userPrefs
    : {};
  const prefSchema =
    payload.donkeycodePrefSchema &&
    typeof payload.donkeycodePrefSchema === "object" &&
    !Array.isArray(payload.donkeycodePrefSchema)
      ? payload.donkeycodePrefSchema
      : {};

  const g = typeof window !== "undefined" ? window : globalThis;
  const key = "__donkeycodeCleanups";
  if (!g[key]) g[key] = Object.create(null);
  const cleanups = g[key];
  if (cleanups[scriptId]) {
    try {
      console.log("[DonkeyCode:page] cleaning up before re-inject", scriptId);
      cleanups[scriptId]();
    } catch (e) {
      console.warn("[DonkeyCode:page] cleanup error before inject", scriptId, e);
    }
    delete cleanups[scriptId];
  }

  function ensureGmBridge() {
    if (g.__donkeycodeGmBridge) return;
    g.__donkeycodeGmBridge = true;
    g.__donkeycodeGmPending = Object.create(null);
    g.__donkeycodeGmNextId = 0;
    g.addEventListener("message", function (ev) {
      if (ev.source !== g) return;
      const d = ev.data;
      if (!d || d.type !== "DONKEYCODE_GM_XHR_RESPONSE") return;
      const rec = g.__donkeycodeGmPending[d.id];
      delete g.__donkeycodeGmPending[d.id];
      if (!rec) return;
      const details = rec.details;
      if (d.error) {
        console.warn("[DonkeyCode:page] GM_xmlhttpRequest error", d.error);
        if (details.onerror) details.onerror({ status: 0, statusText: d.error });
      } else if (details.onload) {
        details.onload({
          responseText: d.responseText || "",
          status: d.status || 0,
          statusText: d.statusText || "",
          finalUrl: d.finalUrl || "",
        });
      }
    });
  }

  function makeGmXmlHttpRequest(sid) {
    ensureGmBridge();
    return function (details) {
      const id = ++g.__donkeycodeGmNextId;
      g.__donkeycodeGmPending[id] = { details: details };
      g.postMessage(
        {
          type: "DONKEYCODE_GM_XHR",
          id: id,
          scriptId: sid,
          details: {
            method: (details && details.method) || "GET",
            url: details && details.url,
            headers: details && details.headers,
          },
        },
        "*"
      );
    };
  }

  /** Normalize @grant tokens: "GM_xmlhttpRequest" / "GM.xmlhttpRequest" → "xmlhttprequest" */
  function canonicalGrant(g) {
    let t = String(g).trim().toLowerCase().replace(/\s+/g, "");
    t = t.replace(/\./g, "_");
    if (t.startsWith("gm_")) t = t.slice(3);
    return t;
  }

  const grantSet = {};
  for (let gi = 0; gi < grants.length; gi++) {
    grantSet[canonicalGrant(grants[gi])] = true;
  }

  const wantsGmByMeta = grantSet["xmlhttprequest"];
  const wantsGmByCode = /\bGM_xmlhttpRequest\b/.test(code);
  const wantsGmXhr = wantsGmByMeta || wantsGmByCode;

  /** Pass GM as a Function arg so nested/async code closes over it. Pages using SES
   * lockdown (e.g. lockdown-install.js) strip globals we add to window — lexical
   * binding survives. */
  let gmImpl;
  if (wantsGmXhr) {
    gmImpl = makeGmXmlHttpRequest(scriptId);
    console.log(
      "[DonkeyCode:page] GM_xmlhttpRequest via closure (SES-safe)",
      scriptId,
      { wantsGmByMeta, wantsGmByCode, connects }
    );
  }

  function donkeycodeGetPref(key) {
    const k = String(key || "");
    if (!k) return undefined;
    if (Object.prototype.hasOwnProperty.call(userPrefs, k)) {
      return userPrefs[k];
    }
    const spec = prefSchema[k];
    if (spec && typeof spec === "object" && Object.prototype.hasOwnProperty.call(spec, "default")) {
      return spec.default;
    }
    return undefined;
  }

  try {
    const prefKeys = Object.keys(userPrefs);
    if (prefKeys.length > 0) {
      console.log("[DonkeyCode:page] applying saved prefs", scriptId, userPrefs);
    }
    console.log(
      "[DonkeyCode:page] executing script",
      scriptId,
      wantsGmXhr ? "+GM_xmlhttpRequest" : ""
    );
    const run = wantsGmXhr
      ? new Function("donkeycodeGetPref", "GM_xmlhttpRequest", code)
      : new Function("donkeycodeGetPref", code);
    /**
     * Lexical parameter from new Function(...) is the primary API.
     * Also assign window/globalThis.donkeycodeGetPref so wrappers can pass
     * globalThis.donkeycodeGetPref into an IIFE, and so async callbacks after
     * the initial run still resolve (last injected script wins if several run).
     */
    g.donkeycodeGetPref = donkeycodeGetPref;
    if (wantsGmXhr) run(donkeycodeGetPref, gmImpl);
    else run(donkeycodeGetPref);
    if (typeof g.__myScriptCleanup === "function") {
      cleanups[scriptId] = g.__myScriptCleanup;
      try {
        delete g.__myScriptCleanup;
      } catch (e) {
        g.__myScriptCleanup = undefined;
      }
      console.log("[DonkeyCode:page] registered __myScriptCleanup", scriptId);
    } else {
      console.log(
        "[DonkeyCode:page] no __myScriptCleanup (optional)",
        scriptId
      );
    }
  } catch (e) {
    console.error("[DonkeyCode:page] script error", scriptId, e);
  }
}

function donkeycodeCleanupMain(scriptId) {
  const g = typeof window !== "undefined" ? window : globalThis;
  const key = "__donkeycodeCleanups";
  const cleanups = g[key];
  if (cleanups && typeof cleanups[scriptId] === "function") {
    try {
      console.log("[DonkeyCode:page] cleanup invoked", scriptId);
      cleanups[scriptId]();
    } catch (e) {
      console.warn("[DonkeyCode:page] cleanup failed", scriptId, e);
    }
    delete cleanups[scriptId];
  } else {
    console.log("[DonkeyCode:page] no cleanup to run", scriptId);
  }
}

function rememberInjection(tabId, scriptId, injected) {
  if (!tabInjectedScripts.has(tabId)) tabInjectedScripts.set(tabId, new Set());
  const set = tabInjectedScripts.get(tabId);
  if (injected) set.add(scriptId);
  else set.delete(scriptId);
}

function forgetScriptEverywhere(scriptId) {
  for (const set of tabInjectedScripts.values()) {
    set.delete(scriptId);
  }
}

function forgetAllInjections() {
  tabInjectedScripts.clear();
}

async function getStoredScripts() {
  const data = await chrome.storage.local.get(STORAGE.SCRIPTS);
  const raw = data[STORAGE.SCRIPTS];
  if (!Array.isArray(raw)) return [];
  return raw.map((s) => ({
    ...s,
    userScriptVersion:
      s && s.userScriptVersion != null && String(s.userScriptVersion).trim() !== ""
        ? String(s.userScriptVersion).trim()
        : "",
    userScriptDescription:
      s && s.userScriptDescription != null && String(s.userScriptDescription).trim() !== ""
        ? String(s.userScriptDescription).trim()
        : "",
    donkeycodePrefSchema:
      s && s.donkeycodePrefSchema && typeof s.donkeycodePrefSchema === "object" && !Array.isArray(s.donkeycodePrefSchema)
        ? s.donkeycodePrefSchema
        : {},
    userPrefs:
      s && s.userPrefs && typeof s.userPrefs === "object" && !Array.isArray(s.userPrefs) ? s.userPrefs : {},
  }));
}

async function saveScripts(scripts) {
  await chrome.storage.local.set({ [STORAGE.SCRIPTS]: scripts });
}

async function getScriptSourceUrl() {
  const data = await chrome.storage.sync.get(STORAGE.SCRIPT_SOURCE);
  return data[STORAGE.SCRIPT_SOURCE] || DEFAULT_SCRIPT_SOURCE_URL;
}

async function getExtraUrls() {
  const data = await chrome.storage.sync.get(STORAGE.EXTRA_URLS);
  const list = data[STORAGE.EXTRA_URLS];
  if (!Array.isArray(list)) return [];
  return list;
}

/**
 * List a directory via GitHub Contents API. Pass **token** when available so
 * requests count as authenticated (much higher rate limits than anonymous IP).
 */
async function fetchGitHubFileList(apiUrl, token) {
  const headers = {
    Accept: "application/vnd.github+json",
    "X-GitHub-Api-Version": "2022-11-28",
  };
  const t = (token || "").trim();
  if (t) headers.Authorization = "Bearer " + t;
  const res = await fetch(apiUrl, { headers, cache: "no-store" });
  const text = await res.text();
  if (!res.ok) {
    let hint = "";
    if (res.status === 403 && /rate limit/i.test(text) && !t) {
      hint =
        " Unauthenticated GitHub API hits a low per-IP limit. Add a personal access token under Settings (same token as session sync) so script refresh uses authenticated rate limits.";
    }
    throw new Error(`GitHub API ${res.status}: ${text}${hint}`);
  }
  let json;
  try {
    json = JSON.parse(text);
  } catch (e) {
    throw new Error("GitHub API: invalid JSON listing response");
  }
  if (!Array.isArray(json)) throw new Error("GitHub API: expected array");
  return json;
}

async function fetchScriptText(url) {
  const res = await fetch(url);
  if (!res.ok) throw new Error(`Fetch script ${res.status}: ${url}`);
  return await res.text();
}

/**
 * Discover .user.js from GitHub Contents API + optional raw URLs.
 */
async function loadScriptsFromRemote() {
  const sourceUrl = await getScriptSourceUrl();
  const extra = await getExtraUrls();
  const ghForList = await getGithubSettings();
  log("loading script list from", sourceUrl, "extras", extra.length);

  const entries = [];

  try {
    const listing = await fetchGitHubFileList(sourceUrl, ghForList.token);
    for (const item of listing) {
      if (item.type !== "file") continue;
      if (!/\.user\.js$/i.test(item.name || "")) continue;
      if (!item.download_url) continue;
      entries.push({
        url: item.download_url,
        name: item.name,
      });
    }
    log("GitHub listing: .user.js count", entries.length);
  } catch (e) {
    logError("GitHub listing failed", e);
    throw e;
  }

  for (const rawUrl of extra) {
    const u = (rawUrl || "").trim();
    if (!u) continue;
    entries.push({
      url: u,
      name: u.split("/").pop() || u,
    });
  }

  const prev = await getStoredScripts();
  const prevByUrl = new Map(prev.map((s) => [s.url, s]));
  const fkRefresh = await getCurrentSessionFolderKey();
  let folderPrefs = await getScriptPrefsMapForFolder(fkRefresh);

  const next = [];
  for (const e of entries) {
    const id = scriptIdFromUrl(e.url);
    const prevRow = prevByUrl.get(e.url);
    let text;
    try {
      text = await fetchScriptText(e.url);
      log("loaded script text", e.name, e.url, "chars", text.length);
    } catch (err) {
      logError("failed to fetch script", e.url, err);
      if (prevRow && prevRow.code) {
        text = prevRow.code;
        logWarn("using cached script body for", e.url);
      } else {
        continue;
      }
    }

    const meta = parseUserScript(text);
    const prefSchema = meta.donkeycodePrefSchema || {};
    const grants =
      meta.grants && meta.grants.length
        ? meta.grants
        : prevRow && prevRow.grants && prevRow.grants.length
          ? prevRow.grants
          : meta.grants || [];
    const connects =
      meta.connects && meta.connects.length
        ? meta.connects
        : prevRow && prevRow.connects && prevRow.connects.length
          ? prevRow.connects
          : meta.connects || [];
    const userScriptName =
      meta.userScriptName ||
      (prevRow && prevRow.userScriptName) ||
      "";
    const userScriptVersion =
      (meta.userScriptVersion && String(meta.userScriptVersion).trim()) ||
      (prevRow && prevRow.userScriptVersion) ||
      "";
    const userScriptDescription =
      (meta.userScriptDescription && String(meta.userScriptDescription).trim()) ||
      (prevRow && prevRow.userScriptDescription) ||
      "";
    const prefRow = folderPrefs[id];
    const useFolderPrefs = !isDefaultSessionFolderKey(fkRefresh);
    let enabledFromFolder;
    if (useFolderPrefs) {
      enabledFromFolder =
        prefRow && Object.prototype.hasOwnProperty.call(folderPrefs, id)
          ? prefRow.enabled !== false
          : false;
    } else {
      enabledFromFolder = prevRow ? prevRow.enabled !== false : false;
    }
    const storedPrefVals =
      prefRow && prefRow.prefs && typeof prefRow.prefs === "object" && !Array.isArray(prefRow.prefs)
        ? prefRow.prefs
        : prevRow && prevRow.userPrefs && typeof prevRow.userPrefs === "object"
          ? prevRow.userPrefs
          : {};
    const userPrefsMerged = mergeUserPrefsWithSchemaDefaults(storedPrefVals, prefSchema);
    next.push({
      id,
      url: e.url,
      name: e.name,
      userScriptName,
      userScriptVersion,
      userScriptDescription,
      enabled: enabledFromFolder,
      donkeycodePrefSchema: prefSchema,
      userPrefs: userPrefsMerged,
      matches: meta.matches,
      excludes: meta.excludes,
      grants,
      connects,
      code: meta.body,
    });
  }

  if (!isDefaultSessionFolderKey(fkRefresh)) {
    const now = Date.now();
    let prefsChanged = false;
    for (const row of next) {
      if (!row.id) continue;
      if (!Object.prototype.hasOwnProperty.call(folderPrefs, row.id)) {
        folderPrefs[row.id] = {
          enabled: false,
          updatedAt: now,
          prefs: {},
        };
        prefsChanged = true;
      }
    }
    if (prefsChanged) {
      await setScriptPrefsMapForFolder(fkRefresh, folderPrefs);
    }
  }

  await saveScripts(next);
  await chrome.storage.local.set({
    [STORAGE.LAST_FETCH]: Date.now(),
  });

  await incrementalReloadScriptsAfterRemoteFetch(prev, next);
  log("scripts saved", next.length);
  updateInstallBadge().catch(() => {});
  return next;
}

async function ensureDailyAlarm() {
  const existing = await chrome.alarms.get(ALARM_DAILY);
  if (!existing) {
    chrome.alarms.create(ALARM_DAILY, { periodInMinutes: 24 * 60 });
    log("created daily alarm");
  }
}

chrome.alarms.onAlarm.addListener((alarm) => {
  if (alarm.name === ALARM_DAILY) {
    log("daily alarm: refreshing scripts");
    loadScriptsFromRemote().catch((e) => logError("daily refresh failed", e));
  }
});

chrome.runtime.onStartup.addListener(() => {
  log("onStartup: refresh scripts");
  ensureHostAccessAndBridge().catch((e) => logError("startup host/bridge", e));
  loadScriptsFromRemote()
    .then(() => updateInstallBadge())
    .catch((e) => {
      logError("startup refresh failed", e);
      updateInstallBadge();
    });
});

chrome.runtime.onInstalled.addListener((details) => {
  log("onInstalled: refresh scripts + alarm", details && details.reason);
  ensureDailyAlarm();
  ensureHostAccessAndBridge().catch((e) => logError("install host/bridge", e));
  loadScriptsFromRemote()
    .then(() => updateInstallBadge())
    .catch((e) => {
      logError("install refresh failed", e);
      updateInstallBadge();
    });
  if (details.reason === "install" || details.reason === "update") {
    chrome.storage.local
      .set({
        [STORAGE.PENDING_INITIAL_SESSION_PULL]: true,
        [STORAGE.PENDING_INITIAL_FOLDER_DISCOVER]: true,
      })
      .catch((e) => logWarn("pending initial session sync flags", e));
  }
  if (details.reason === "install") {
    const url = chrome.runtime.getURL("welcome.html");
    chrome.tabs.create({ url }).catch((e) => logWarn("welcome tab", e));
  } else {
    updateInstallBadge().catch(() => {});
  }
});

chrome.tabs.onRemoved.addListener((tabId) => {
  tabInjectedScripts.delete(tabId);
});

/**
 * @param {number} tabId
 * @param {string} url
 */
async function syncTabScripts(tabId, url) {
  if (!url || url.startsWith("chrome://") || url.startsWith("devtools://"))
    return;

  if (!(await hasOriginAccessForUrl(url))) {
    log("skip inject (no optional host permission for origin)", url);
    return;
  }

  const scripts = await getStoredScripts();
  for (const script of scripts) {
    if (!script.enabled) continue;
    if (!script.code) continue;
    if (!scriptMatchesUrl(script, url)) continue;

    const set = tabInjectedScripts.get(tabId) || new Set();
    if (set.has(script.id)) continue;

    try {
      await chrome.scripting.executeScript({
        target: { tabId, allFrames: false },
        world: "MAIN",
        func: donkeycodeInjectMain,
        args: [
          {
            id: script.id,
            code: script.code,
            grants: script.grants || [],
            connects: script.connects || [],
            userPrefs: script.userPrefs || {},
            donkeycodePrefSchema: script.donkeycodePrefSchema || {},
          },
        ],
      });
      rememberInjection(tabId, script.id, true);
      log("injected script", script.id, script.name, "tab", tabId, url);
    } catch (e) {
      logError("inject failed", script.id, tabId, e);
    }
  }
}

chrome.tabs.onUpdated.addListener((tabId, changeInfo, tab) => {
  if (changeInfo.status === "complete" && tab && tab.url) {
    maybeEnsurePerTabZoomOnNavigation(tabId, tab.url).catch(() => {});
  }
  if (changeInfo.status !== "complete" || !tab.url) return;
  tabInjectedScripts.delete(tabId);
  syncTabScripts(tabId, tab.url).catch((e) => logError("syncTabScripts", e));
});

/** Same as https://github.com/xinan/zoom-per-tab — keep zoom mode per-tab after user adjusts zoom. */
if (chrome.tabs && chrome.tabs.onZoomChange) {
  chrome.tabs.onZoomChange.addListener((zoomChangeInfo) => {
    const tid = zoomChangeInfo && zoomChangeInfo.tabId;
    if (tid != null) ensurePerTabZoomForTab(tid).catch(() => {});
  });
}

/**
 * Re-run matching for all tabs (after toggle or refresh).
 */
async function resyncAllTabs() {
  const tabs = await chrome.tabs.query({});
  for (const t of tabs) {
    if (!t.id || !t.url) continue;
    await syncTabScripts(t.id, t.url);
  }
}

async function cleanupScriptEverywhere(scriptId) {
  const tabs = await chrome.tabs.query({});
  for (const t of tabs) {
    if (!t.id) continue;
    try {
      await chrome.scripting.executeScript({
        target: { tabId: t.id, allFrames: false },
        world: "MAIN",
        func: donkeycodeCleanupMain,
        args: [scriptId],
      });
      log("cleanup dispatched", scriptId, "tab", t.id);
    } catch (e) {
      logWarn("cleanup failed for tab", t.id, e);
    }
    const set = tabInjectedScripts.get(t.id);
    if (set) set.delete(scriptId);
  }
}

/** Deterministic JSON-like string for comparing script inject payloads (key order stable for objects). */
function stableStringify(value) {
  if (value === null) return "null";
  const t = typeof value;
  if (t === "number" || t === "boolean") return JSON.stringify(value);
  if (t === "string") return JSON.stringify(value);
  if (Array.isArray(value)) {
    return "[" + value.map(stableStringify).join(",") + "]";
  }
  if (t === "object") {
    const keys = Object.keys(value).sort();
    return "{" + keys.map((k) => JSON.stringify(k) + ":" + stableStringify(value[k])).join(",") + "}";
  }
  return JSON.stringify(String(value));
}

/**
 * Fingerprint of everything that affects MAIN-world injection for a script row.
 * If unchanged, existing injections stay valid and we skip cleanup/resync for that script.
 */
function computeScriptInjectionKey(script) {
  const o = {
    enabled: script.enabled !== false,
    code: script.code || "",
    matches: script.matches || [],
    excludes: script.excludes || [],
    grants: script.grants || [],
    connects: script.connects || [],
    userPrefs: script.userPrefs && typeof script.userPrefs === "object" && !Array.isArray(script.userPrefs) ? script.userPrefs : {},
    donkeycodePrefSchema:
      script.donkeycodePrefSchema && typeof script.donkeycodePrefSchema === "object" && !Array.isArray(script.donkeycodePrefSchema)
        ? script.donkeycodePrefSchema
        : {},
  };
  return stableStringify(o);
}

/**
 * Re-inject only for tabs that match at least one of the given script ids (after clearing those ids from the per-tab set).
 * Skips tabs that would not run any of these scripts.
 */
async function resyncTabsForScriptIds(scriptIds) {
  if (!scriptIds || scriptIds.length === 0) return;
  const idSet = new Set(scriptIds);
  const scripts = await getStoredScripts();
  const byId = new Map(scripts.map((s) => [s.id, s]));
  const tabs = await chrome.tabs.query({});
  for (const t of tabs) {
    if (!t.id || !t.url) continue;
    if (!(await hasOriginAccessForUrl(t.url))) continue;
    let anyMatch = false;
    for (const sid of idSet) {
      const sc = byId.get(sid);
      if (!sc || !sc.enabled || !sc.code) continue;
      if (scriptMatchesUrl(sc, t.url)) {
        anyMatch = true;
        break;
      }
    }
    if (!anyMatch) continue;
    for (const sid of idSet) {
      const sc = byId.get(sid);
      if (!sc || !sc.enabled || !sc.code) continue;
      if (!scriptMatchesUrl(sc, t.url)) continue;
      const set = tabInjectedScripts.get(t.id) || new Set();
      if (set.has(sid)) set.delete(sid);
    }
    await syncTabScripts(t.id, t.url);
  }
}

/**
 * After fetching scripts from remote: only tear down + re-inject scripts that were removed or changed.
 * Avoids re-running every user script on every tab when nothing (or little) changed.
 */
async function incrementalReloadScriptsAfterRemoteFetch(prev, next) {
  const prevById = new Map(prev.map((s) => [s.id, s]));
  const nextById = new Map(next.map((s) => [s.id, s]));
  const removedIds = [];
  for (const id of prevById.keys()) {
    if (!nextById.has(id)) removedIds.push(id);
  }
  const changedIds = [];
  for (const [id, s] of nextById) {
    const p = prevById.get(id);
    const newKey = computeScriptInjectionKey(s);
    const oldKey = p ? computeScriptInjectionKey(p) : null;
    if (oldKey !== newKey) changedIds.push(id);
  }
  if (removedIds.length === 0 && changedIds.length === 0) {
    log("incremental script reload: no changes");
    return;
  }
  for (const id of removedIds) {
    await cleanupScriptEverywhere(id);
  }
  for (const id of changedIds) {
    if (prevById.has(id)) {
      await cleanupScriptEverywhere(id);
    }
  }
  const toResync = changedIds.filter((id) => nextById.has(id));
  await resyncTabsForScriptIds(toResync);
  log("incremental script reload", {
    removed: removedIds.length,
    changed: changedIds.length,
    resyncedIds: toResync.length,
  });
}

async function toggleScript(scriptId, enabled) {
  const scripts = await getStoredScripts();
  const idx = scripts.findIndex((s) => s.id === scriptId);
  if (idx < 0) throw new Error("Script not found");
  scripts[idx].enabled = enabled;
  await saveScripts(scripts);
  const fk = await getCurrentSessionFolderKey();
  const map = await getScriptPrefsMapForFolder(fk);
  const prev = map[scriptId] || {};
  const prevP = prev.prefs && typeof prev.prefs === "object" && !Array.isArray(prev.prefs) ? prev.prefs : {};
  const up =
    scripts[idx].userPrefs && typeof scripts[idx].userPrefs === "object" && !Array.isArray(scripts[idx].userPrefs)
      ? scripts[idx].userPrefs
      : {};
  map[scriptId] = {
    enabled,
    updatedAt: Date.now(),
    prefs: Object.assign({}, prevP, up),
  };
  await setScriptPrefsMapForFolder(fk, map);
  log("toggle script", scriptId, enabled);

  if (!enabled) {
    await cleanupScriptEverywhere(scriptId);
  } else {
    forgetScriptEverywhere(scriptId);
    await resyncAllTabs();
  }
  updateInstallBadge().catch(() => {});
}

/** OpsSuite worksheet tabs — stable restore order + stagger helps server-side numbering. */
const WORKSHEET_HOST = "opssuitemain.swacorp.com";
const WORKSHEET_PATH_MARK = "/widgets/worksheet";

function isOpsSuiteWorksheetUrl(url) {
  if (!url || typeof url !== "string") return false;
  try {
    const u = new URL(url);
    return (
      u.hostname === WORKSHEET_HOST &&
      u.pathname.toLowerCase().indexOf(WORKSHEET_PATH_MARK) !== -1
    );
  } catch (e) {
    return false;
  }
}

function sessionHasWorksheetTabs(snap) {
  if (!snap || !Array.isArray(snap.windows)) return false;
  for (const w of snap.windows) {
    for (const t of w.tabs || []) {
      if (isOpsSuiteWorksheetUrl(t.url)) return true;
    }
  }
  return false;
}

function worksheetPrimaryUrlForWindow(w) {
  for (const t of w.tabs || []) {
    if (isOpsSuiteWorksheetUrl(t.url)) return String(t.url);
  }
  return "";
}

/** First worksheet tab title (OpsSuite worksheet URLs are often identical). */
function worksheetPrimaryTitleForWindow(w) {
  for (const t of w.tabs || []) {
    if (isOpsSuiteWorksheetUrl(t.url)) {
      const tit = t.title != null ? String(t.title).trim() : "";
      return tit;
    }
  }
  return "";
}

/**
 * Deterministic order: optional `restoreOrder` (lower first), then worksheet URL,
 * then worksheet tab title, then original index.
 */
function sortWindowsForRestore(windows) {
  return windows
    .map((w, i) => ({ w, i }))
    .sort((A, B) => {
      const a = A.w;
      const b = B.w;
      const roA = typeof a.restoreOrder === "number" ? a.restoreOrder : 1e9;
      const roB = typeof b.restoreOrder === "number" ? b.restoreOrder : 1e9;
      if (roA !== roB) return roA - roB;
      const wa = worksheetPrimaryUrlForWindow(a);
      const wb = worksheetPrimaryUrlForWindow(b);
      if (wa && wb && wa !== wb) return wa.localeCompare(wb);
      if (wa && !wb) return -1;
      if (!wa && wb) return 1;
      const ta = worksheetPrimaryTitleForWindow(a);
      const tb = worksheetPrimaryTitleForWindow(b);
      if (ta && tb && ta !== tb) return ta.localeCompare(tb);
      if (ta && !tb) return -1;
      if (!ta && tb) return 1;
      return A.i - B.i;
    })
    .map((x) => x.w);
}

function delayMs(ms) {
  return new Promise(function (resolve) {
    setTimeout(resolve, ms);
  });
}

/**
 * Chrome defaults zoom to per-origin; `scope: "per-tab"` matches extensions like
 * https://github.com/xinan/zoom-per-tab — each tab can have its own zoom for the same site.
 */
async function ensurePerTabZoomForTab(tabId) {
  if (tabId == null) return;
  try {
    await chrome.tabs.setZoomSettings(tabId, { scope: "per-tab" });
  } catch (e) {
    /* ignore */
  }
}

async function applySavedZoomToTab(tabId, zoomFactor) {
  const z =
    typeof zoomFactor === "number" && Number.isFinite(zoomFactor)
      ? clampTabZoom(zoomFactor)
      : 1;
  try {
    await ensurePerTabZoomForTab(tabId);
    await chrome.tabs.setZoom(tabId, z);
  } catch (e) {
    logWarn("applySavedZoomToTab", tabId, e);
  }
}

/** After load, set per-tab zoom mode so Ctrl+/wheel only affects this tab (same as Zoom Per Tab). */
async function maybeEnsurePerTabZoomOnNavigation(tabId, url) {
  if (tabId == null || !url) return;
  if (!/^https?:\/\//i.test(url) || String(url).startsWith("chrome-extension:")) {
    return;
  }
  await ensurePerTabZoomForTab(tabId);
}

async function applyPerTabZoomScopeToOpenHttpTabs() {
  try {
    const tabs = await chrome.tabs.query({});
    for (const t of tabs) {
      if (!t.id || !t.url) continue;
      if (!/^https?:\/\//i.test(t.url)) continue;
      if (String(t.url).startsWith("chrome-extension:")) continue;
      await ensurePerTabZoomForTab(t.id);
    }
  } catch (e) {
    logWarn("applyPerTabZoomScopeToOpenHttpTabs", e);
  }
}

/**
 * Close normal tabs that show a given extension page (e.g. popup opened as a fallback tab).
 */
async function closeTabsShowingExtensionPath(relativePath) {
  const rel = String(relativePath || "")
    .trim()
    .replace(/^\/+/, "");
  if (!rel) return;
  let targetUrl;
  try {
    targetUrl = chrome.runtime.getURL(rel);
  } catch (e) {
    return;
  }
  try {
    const tabs = await chrome.tabs.query({ url: targetUrl });
    for (const t of tabs) {
      if (t.id == null) continue;
      try {
        await chrome.tabs.remove(t.id);
        log("closed extension page tab", rel, t.id);
      } catch (e) {
        logWarn("closeTabsShowingExtensionPath remove", t.id, e);
      }
    }
  } catch (e) {
    logWarn("closeTabsShowingExtensionPath query", e);
  }
}

/** After Login First, close login windows only once the session has started (avoids killing the browser too early). */
const LOGIN_FLOW_CLOSE_AFTER_FIRST_WINDOW_MS = 500;

/** Chrome tab zoom range (fraction of default). */
function clampTabZoom(z) {
  const n = Number(z);
  if (!Number.isFinite(n)) return 1;
  return Math.min(5, Math.max(0.25, n));
}

async function getSessionSaveZoomEnabled() {
  const d = await chrome.storage.local.get(STORAGE.SESSION_SAVE_ZOOM_PER_TAB);
  if (d[STORAGE.SESSION_SAVE_ZOOM_PER_TAB] === false) return false;
  return true;
}

function normalizeSessionSnapshot(snap) {
  if (!snap || !Array.isArray(snap.windows)) {
    const empty = { windows: [], _meta: { updatedAt: 0 } };
    if (snap && snap._meta && typeof snap._meta === "object") {
      empty._meta = {
        updatedAt: Number(snap._meta.updatedAt) || 0,
      };
      if (typeof snap._meta.worksheetStaggerMs === "number") {
        empty._meta.worksheetStaggerMs = snap._meta.worksheetStaggerMs;
      }
    }
    return empty;
  }
  const windows = snap.windows.map((w, wi) => {
    const id =
      w.id && String(w.id).trim()
        ? String(w.id)
        : "w_" + wi + "_" + Math.random().toString(36).slice(2, 9);
    const tabs = (w.tabs || []).map((t, ti) => {
      const row = {
        url: t.url != null ? String(t.url) : "",
        active: !!t.active,
        index: typeof t.index === "number" ? t.index : ti,
        pinned: !!t.pinned,
      };
      if (t.title != null && String(t.title).trim()) {
        row.title = String(t.title).trim();
      }
      if (typeof t.zoomFactor === "number" && Number.isFinite(t.zoomFactor)) {
        row.zoomFactor = clampTabZoom(t.zoomFactor);
      }
      return row;
    });
    const win = {
      id,
      left: w.left,
      top: w.top,
      width: w.width,
      height: w.height,
      state: w.state,
      focused: w.focused,
      tabs,
    };
    if (typeof w.restoreOrder === "number") win.restoreOrder = w.restoreOrder;
    return win;
  });
  const out = { windows };
  if (snap._meta && typeof snap._meta === "object") {
    out._meta = { updatedAt: Number(snap._meta.updatedAt) || 0 };
    if (typeof snap._meta.worksheetStaggerMs === "number") {
      out._meta.worksheetStaggerMs = snap._meta.worksheetStaggerMs;
    }
  } else {
    out._meta = { updatedAt: 0 };
  }
  return out;
}

function touchSessionMeta(snap) {
  const n = normalizeSessionSnapshot(snap);
  const prev = n._meta && typeof n._meta === "object" ? n._meta : {};
  n._meta = { ...prev, updatedAt: Date.now() };
  return n;
}

const DEFAULT_SESSION_FOLDER = "__default__";

function normalizeFolderKey(name) {
  const t = (name || "").trim().replace(/\\/g, "/");
  if (!t) return DEFAULT_SESSION_FOLDER;
  return t.replace(/^\/+|\/+$/g, "") || DEFAULT_SESSION_FOLDER;
}

function folderGithubSegments(folderEntry, folderKey) {
  const fk = normalizeFolderKey(folderKey);
  const manual = (folderEntry && folderEntry.githubRelativePath
    ? String(folderEntry.githubRelativePath)
    : ""
  )
    .trim()
    .replace(/\\/g, "/");
  if (manual) {
    return manual
      .split("/")
      .map((s) => s.trim())
      .filter(Boolean);
  }
  if (fk === DEFAULT_SESSION_FOLDER) return [];
  return fk
    .split("/")
    .map((s) => s.trim())
    .filter(Boolean);
}

/**
 * Session snapshots are large; chrome.storage.sync limits each key to ~8KB.
 * Store session folder data in chrome.storage.local (much higher per-item limits).
 * One-time migration from sync (and legacy flat SESSIONS) into local.
 */
async function migrateSessionStorageToLocalIfNeeded() {
  const done = await chrome.storage.local.get(STORAGE.SESSION_STORAGE_MIGRATED);
  if (done[STORAGE.SESSION_STORAGE_MIGRATED]) return;

  const syncPack = await chrome.storage.sync.get([
    STORAGE.SESSION_FOLDERS_V2,
    STORAGE.CURRENT_SESSION_FOLDER,
    STORAGE.SESSIONS,
  ]);
  let folders = syncPack[STORAGE.SESSION_FOLDERS_V2];
  if (!folders || typeof folders !== "object" || Array.isArray(folders)) {
    folders = {};
  }

  const legacy = syncPack[STORAGE.SESSIONS];
  if (legacy && typeof legacy === "object" && Object.keys(legacy).length) {
    if (!folders[DEFAULT_SESSION_FOLDER]) folders[DEFAULT_SESSION_FOLDER] = { sessions: {} };
    const existing = folders[DEFAULT_SESSION_FOLDER].sessions || {};
    folders[DEFAULT_SESSION_FOLDER].sessions = { ...legacy, ...existing };
    log("migration: merged legacy flat sessions into", DEFAULT_SESSION_FOLDER);
  }

  if (!folders[DEFAULT_SESSION_FOLDER]) {
    folders[DEFAULT_SESSION_FOLDER] = { sessions: {} };
  }

  let cur = (syncPack[STORAGE.CURRENT_SESSION_FOLDER] || "").trim() || DEFAULT_SESSION_FOLDER;
  cur = normalizeFolderKey(cur);
  if (!folders[cur]) folders[cur] = { sessions: {} };

  await chrome.storage.local.set({
    [STORAGE.SESSION_FOLDERS_V2]: folders,
    [STORAGE.CURRENT_SESSION_FOLDER]: cur,
    [STORAGE.SESSION_STORAGE_MIGRATED]: true,
  });

  try {
    await chrome.storage.sync.remove([
      STORAGE.SESSION_FOLDERS_V2,
      STORAGE.CURRENT_SESSION_FOLDER,
      STORAGE.SESSIONS,
      STORAGE.SESSIONS_LEGACY_MIGRATED,
    ]);
  } catch (e) {
    logWarn("migration: could not remove old sync session keys", e);
  }

  log("sessions storage migrated to chrome.storage.local");
}

function normalizeScriptPrefsEntry(row) {
  if (!row || typeof row !== "object") {
    return { enabled: false, updatedAt: 0, prefs: {} };
  }
  const enabled = row.enabled !== false;
  const updatedAt = Number(row.updatedAt) || 0;
  const prefs =
    row.prefs && typeof row.prefs === "object" && !Array.isArray(row.prefs)
      ? row.prefs
      : {};
  return { enabled, updatedAt, prefs };
}

function normalizeScriptPrefsMap(raw) {
  const out = {};
  if (!raw || typeof raw !== "object" || Array.isArray(raw)) return out;
  for (const [k, v] of Object.entries(raw)) {
    if (!k || typeof k !== "string") continue;
    out[k] = normalizeScriptPrefsEntry(v);
  }
  return out;
}

function isDefaultSessionFolderKey(folderKey) {
  return normalizeFolderKey(folderKey) === DEFAULT_SESSION_FOLDER;
}

async function getScriptPrefsMapForFolder(folderKey) {
  const fk = normalizeFolderKey(folderKey);
  if (isDefaultSessionFolderKey(fk)) {
    return {};
  }
  const { folders } = await getSessionFoldersState();
  const entry = folders[fk] || {};
  const raw = entry.scriptPrefs;
  return normalizeScriptPrefsMap(raw);
}

async function setScriptPrefsMapForFolder(folderKey, map) {
  const fk = normalizeFolderKey(folderKey);
  if (isDefaultSessionFolderKey(fk)) {
    return;
  }
  const { folders } = await getSessionFoldersState();
  if (!folders[fk]) folders[fk] = { sessions: {}, scriptPrefs: {} };
  if (!folders[fk].sessions || typeof folders[fk].sessions !== "object") {
    folders[fk].sessions = {};
  }
  folders[fk].scriptPrefs = normalizeScriptPrefsMap(map);
  await chrome.storage.local.set({ [STORAGE.SESSION_FOLDERS_V2]: folders });
}

/**
 * Copy current global script enabled flags into a folder's scriptPrefs (call before switching folders).
 */
async function persistCurrentFolderScriptPrefsFromStorage() {
  const fk = await getCurrentSessionFolderKey();
  if (isDefaultSessionFolderKey(fk)) {
    return;
  }
  const scripts = await getStoredScripts();
  const map = await getScriptPrefsMapForFolder(fk);
  const now = Date.now();
  for (const s of scripts) {
    if (!s || !s.id) continue;
    const prev = map[s.id] || {};
    const prevObj = prev.prefs && typeof prev.prefs === "object" && !Array.isArray(prev.prefs) ? prev.prefs : {};
    const scriptPrefs =
      s.userPrefs && typeof s.userPrefs === "object" && !Array.isArray(s.userPrefs) ? s.userPrefs : {};
    map[s.id] = {
      enabled: s.enabled !== false,
      updatedAt: now,
      prefs: Object.assign({}, prevObj, scriptPrefs),
    };
  }
  await setScriptPrefsMapForFolder(fk, map);
}

/**
 * Apply a folder's scriptPrefs onto the global scripts array (enabled + future prefs), then save.
 * Default folder has no stored prefs — leave global script toggles unchanged.
 */
async function applyScriptPrefsFromFolderToStorage(folderKey) {
  const fk = normalizeFolderKey(folderKey);
  if (isDefaultSessionFolderKey(fk)) {
    return;
  }
  const scripts = await getStoredScripts();
  const prefs = await getScriptPrefsMapForFolder(folderKey);
  const next = scripts.map(function (s) {
    const p = prefs[s.id];
    const enabled = p ? p.enabled !== false : false;
    const o = Object.assign({}, s);
    o.enabled = enabled;
    const rawStored = p && p.prefs && typeof p.prefs === "object" && !Array.isArray(p.prefs) ? p.prefs : {};
    const schema = o.donkeycodePrefSchema || {};
    o.userPrefs = mergeUserPrefsWithSchemaDefaults(rawStored, schema);
    return o;
  });
  await saveScripts(next);
  forgetAllInjections();
  await resyncAllTabs();
  updateInstallBadge().catch(() => {});
}

async function getSessionFoldersState() {
  await migrateSessionStorageToLocalIfNeeded();
  const d = await chrome.storage.local.get([
    STORAGE.SESSION_FOLDERS_V2,
    STORAGE.CURRENT_SESSION_FOLDER,
  ]);
  let folders = d[STORAGE.SESSION_FOLDERS_V2];
  if (!folders || typeof folders !== "object" || Array.isArray(folders)) {
    folders = {};
  }
  if (!folders[DEFAULT_SESSION_FOLDER]) {
    folders[DEFAULT_SESSION_FOLDER] = { sessions: {}, scriptPrefs: {} };
  }
  let cur = (d[STORAGE.CURRENT_SESSION_FOLDER] || "").trim() || DEFAULT_SESSION_FOLDER;
  cur = normalizeFolderKey(cur);
  if (!folders[cur]) folders[cur] = { sessions: {}, scriptPrefs: {} };
  for (const k of Object.keys(folders)) {
    const ent = folders[k];
    if (!ent || typeof ent !== "object") {
      folders[k] = { sessions: {}, scriptPrefs: {} };
      continue;
    }
    if (!ent.sessions || typeof ent.sessions !== "object" || Array.isArray(ent.sessions)) {
      ent.sessions = {};
    }
    if (!ent.scriptPrefs || typeof ent.scriptPrefs !== "object" || Array.isArray(ent.scriptPrefs)) {
      ent.scriptPrefs = {};
    }
  }
  return { folders, currentKey: cur };
}

async function getCurrentSessionFolderKey() {
  const { currentKey } = await getSessionFoldersState();
  return currentKey;
}

async function getSessionsMapForFolder(folderKey) {
  const { folders } = await getSessionFoldersState();
  const fk = normalizeFolderKey(folderKey);
  const entry = folders[fk] || { sessions: {} };
  const raw =
    entry.sessions &&
    typeof entry.sessions === "object" &&
    !Array.isArray(entry.sessions)
      ? entry.sessions
      : {};
  const out = {};
  for (const k of Object.keys(raw)) {
    out[k] = normalizeSessionSnapshot(raw[k]);
  }
  return out;
}

async function setSessionsMapForFolder(folderKey, sessionsObj) {
  const { folders } = await getSessionFoldersState();
  const fk = normalizeFolderKey(folderKey);
  if (!folders[fk]) folders[fk] = { sessions: {} };
  const map =
    sessionsObj && typeof sessionsObj === "object" && !Array.isArray(sessionsObj)
      ? sessionsObj
      : {};
  folders[fk].sessions = map;
  await chrome.storage.local.set({ [STORAGE.SESSION_FOLDERS_V2]: folders });
}

