function mergeSessionsByTimestamp(localMap, remoteMap) {
  const names = new Set([
    ...Object.keys(localMap || {}),
    ...Object.keys(remoteMap || {}),
  ]);
  const merged = {};
  for (const name of names) {
    const L = localMap[name];
    const R = remoteMap[name];
    const tL = L && L._meta ? Number(L._meta.updatedAt) || 0 : 0;
    const tR = R && R._meta ? Number(R._meta.updatedAt) || 0 : 0;
    if (!L) merged[name] = normalizeSessionSnapshot(R);
    else if (!R) merged[name] = normalizeSessionSnapshot(L);
    else if (tR > tL) merged[name] = normalizeSessionSnapshot(R);
    else merged[name] = normalizeSessionSnapshot(L);
  }
  return merged;
}

/**
 * Merge for **uploading** to GitHub: local session list is authoritative for **which names exist**.
 * If a name was removed locally, do not re-add it from remote (fixes deletes reappearing after push).
 * For names in both, newer `updatedAt` wins (same as pull merge).
 */
function mergeSessionsForPush(localMap, remoteMap) {
  const L = localMap || {};
  const R = remoteMap || {};
  const merged = {};
  for (const name of Object.keys(L)) {
    const loc = L[name];
    const rem = R[name];
    if (!rem) {
      merged[name] = normalizeSessionSnapshot(loc);
      continue;
    }
    const tL = loc && loc._meta ? Number(loc._meta.updatedAt) || 0 : 0;
    const tR = rem && rem._meta ? Number(rem._meta.updatedAt) || 0 : 0;
    merged[name] =
      tR > tL ? normalizeSessionSnapshot(rem) : normalizeSessionSnapshot(loc);
  }
  return merged;
}

function sessionsToGithubFilePayload(sessionsMap) {
  return {
    version: 1,
    updatedAt: Date.now(),
    sessions: sessionsMap,
  };
}

function sessionsFromGithubFilePayload(parsed) {
  if (!parsed || typeof parsed !== "object") return {};
  if (parsed.sessions && typeof parsed.sessions === "object") {
    const out = {};
    for (const [k, v] of Object.entries(parsed.sessions)) {
      out[k] = normalizeSessionSnapshot(v);
    }
    return out;
  }
  return {};
}

function scriptPrefsToGithubFilePayload(map) {
  return {
    version: 1,
    updatedAt: Date.now(),
    scriptPrefs: normalizeScriptPrefsMap(map),
  };
}

function scriptPrefsFromGithubFilePayload(parsed) {
  if (!parsed || typeof parsed !== "object") return {};
  if (parsed.scriptPrefs && typeof parsed.scriptPrefs === "object") {
    return normalizeScriptPrefsMap(parsed.scriptPrefs);
  }
  return {};
}

function mergeScriptPrefsByTimestamp(localMap, remoteMap) {
  const L = normalizeScriptPrefsMap(localMap);
  const R = normalizeScriptPrefsMap(remoteMap);
  const ids = new Set([...Object.keys(L), ...Object.keys(R)]);
  const merged = {};
  for (const id of ids) {
    const a = L[id];
    const b = R[id];
    if (!a) merged[id] = normalizeScriptPrefsEntry(b);
    else if (!b) merged[id] = normalizeScriptPrefsEntry(a);
    else {
      const tA = a.updatedAt || 0;
      const tB = b.updatedAt || 0;
      merged[id] = tB > tA ? normalizeScriptPrefsEntry(b) : normalizeScriptPrefsEntry(a);
    }
  }
  return merged;
}

/** Explicit "Get prefs" from cloud: remote wins when present (fixes equal-timestamp ties). */
function mergeScriptPrefsPreferRemote(localMap, remoteMap) {
  const L = normalizeScriptPrefsMap(localMap);
  const R = normalizeScriptPrefsMap(remoteMap);
  const ids = new Set([...Object.keys(L), ...Object.keys(R)]);
  const merged = {};
  for (const id of ids) {
    if (Object.prototype.hasOwnProperty.call(R, id)) {
      merged[id] = normalizeScriptPrefsEntry(R[id]);
    } else {
      merged[id] = normalizeScriptPrefsEntry(L[id]);
    }
  }
  return merged;
}

function mergeScriptPrefsForPush(localMap, remoteMap) {
  const L = normalizeScriptPrefsMap(localMap);
  const R = normalizeScriptPrefsMap(remoteMap);
  const merged = Object.assign({}, R);
  for (const id of Object.keys(L)) {
    const loc = L[id];
    const rem = R[id];
    if (!rem) {
      merged[id] = normalizeScriptPrefsEntry(loc);
      continue;
    }
    const tL = loc.updatedAt || 0;
    const tR = rem.updatedAt || 0;
    merged[id] = tR > tL ? normalizeScriptPrefsEntry(rem) : normalizeScriptPrefsEntry(loc);
  }
  return merged;
}

function utf8ToBase64(str) {
  return btoa(unescape(encodeURIComponent(str)));
}

function base64ToUtf8(b64) {
  return decodeURIComponent(escape(atob(b64)));
}

async function githubApiRequest(path, options, token) {
  const url = path.startsWith("http") ? path : "https://api.github.com" + path;
  const headers = {
    Accept: "application/vnd.github+json",
    "X-GitHub-Api-Version": "2022-11-28",
    ...(options.headers || {}),
  };
  if (token) headers.Authorization = "Bearer " + token;
  /** Avoid stale cached responses (wrong blob sha on GET → "does not match" on PUT). */
  const res = await fetch(url, { ...options, headers, cache: "no-store" });
  const text = await res.text();
  let json = null;
  try {
    json = text ? JSON.parse(text) : null;
  } catch (e) {
    json = null;
  }
  if (!res.ok) {
    let msg = (json && json.message) || text || "HTTP " + res.status;
    if (json && Array.isArray(json.errors) && json.errors.length) {
      const parts = json.errors
        .map((er) => (er && (er.message || String(er.code || ""))) || "")
        .filter(Boolean);
      if (parts.length) {
        msg = msg + (/\.\s*$/.test(msg) ? " " : ". ") + parts.join("; ");
      }
    }
    const err = new Error(msg);
    err.status = res.status;
    err.githubJson = json;
    throw err;
  }
  return json;
}

/** Full text for matching (top-level message + errors[].message on 422). */
function githubApiErrorFullText(e) {
  let s = String(e && e.message ? e.message : e);
  const j = e && e.githubJson;
  if (j && Array.isArray(j.errors)) {
    for (const er of j.errors) {
      if (er && er.message) s += " " + er.message;
    }
  }
  return s;
}

async function getGithubSettings() {
  await migrateGithubSessionsRootIfNeeded();
  const data = await chrome.storage.local.get([
    STORAGE.GITHUB_PAT,
    STORAGE.GITHUB_OWNER,
    STORAGE.GITHUB_REPO,
    STORAGE.GITHUB_BRANCH,
    STORAGE.GITHUB_PATH,
    STORAGE.GITHUB_SESSIONS_ROOT,
  ]);
  const baked = self.BAKED_GITHUB_DEFAULTS || {};
  const token =
    (data[STORAGE.GITHUB_PAT] || "").trim() || String(baked.token || "").trim();
  const owner =
    (data[STORAGE.GITHUB_OWNER] || "").trim() || String(baked.owner || "").trim();
  const repo =
    (data[STORAGE.GITHUB_REPO] || "").trim() || String(baked.repo || "").trim();
  const branchRaw =
    (data[STORAGE.GITHUB_BRANCH] || "").trim() ||
    String(baked.branch || "main").trim() ||
    "main";
  const branch = branchRaw || "main";
  const pathRaw =
    (data[STORAGE.GITHUB_PATH] || "").trim() ||
    String(baked.path || "sessions/donkeycode-sessions.json").trim();
  const legacyPath = (pathRaw || "sessions/donkeycode-sessions.json").replace(
    /^\/+/,
    ""
  );
  let sessionsRoot = (data[STORAGE.GITHUB_SESSIONS_ROOT] || "").trim();
  if (!sessionsRoot) {
    sessionsRoot = deriveSessionsRootFromLegacyPath(legacyPath);
  }
  const path = defaultSessionFilePathForRoot(sessionsRoot);
  return { token, owner, repo, branch, path, sessionsRoot };
}

/**
 * Create a GitHub Issue in the configured repo. The returned issue **number** is the INC reference.
 * PAT must include the `issues` scope (classic) or Issues write (fine-grained).
 */
async function createGithubIssueReport(title, body, labelNames) {
  const gh = await getGithubSettings();
  if (!gh.token || !gh.owner || !gh.repo) {
    throw new Error("Configure GitHub owner, repo, and token in Settings to report issues.");
  }
  const t = (title || "").trim();
  if (!t) throw new Error("Title is required");
  const b = (body || "").trim();
  const payload = {
    title: t.length > 240 ? t.slice(0, 237) + "…" : t,
    body:
      b ||
      "(no description provided)\n\n---\n_Report submitted from DonkeyCode._",
  };
  const labels = Array.isArray(labelNames)
    ? labelNames.map((x) => String(x || "").trim()).filter(Boolean)
    : [];
  if (labels.length) payload.labels = labels;
  const apiPath =
    "/repos/" +
    encodeURIComponent(gh.owner) +
    "/" +
    encodeURIComponent(gh.repo) +
    "/issues";
  const json = await githubApiRequest(
    apiPath,
    {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(payload),
    },
    gh.token
  );
  const num = json && json.number != null ? Number(json.number) : NaN;
  const htmlUrl = json && json.html_url ? String(json.html_url) : "";
  if (!Number.isFinite(num)) {
    throw new Error("GitHub did not return an issue number.");
  }
  return { number: num, htmlUrl, nodeId: json.node_id };
}

async function fetchGithubSessionsFile(settings) {
  const { token, owner, repo, branch, path } = settings;
  if (!token || !owner || !repo) throw new Error("GitHub owner, repo, and token required");
  const pathSeg = path
    .split("/")
    .map((p) => encodeURIComponent(p))
    .join("/");
  const apiPath =
    "/repos/" +
    encodeURIComponent(owner) +
    "/" +
    encodeURIComponent(repo) +
    "/contents/" +
    pathSeg +
    "?ref=" +
    encodeURIComponent(branch);
  let json;
  try {
    json = await githubApiRequest(apiPath, { method: "GET" }, token);
  } catch (e) {
    if (e && e.status === 404) return null;
    throw e;
  }
  if (!json || json.type !== "file" || !json.content) {
    throw new Error("Unexpected GitHub API response for file");
  }
  const raw = base64ToUtf8(json.content.replace(/\s/g, ""));
  const parsed = JSON.parse(raw);
  return { sha: json.sha, sessions: sessionsFromGithubFilePayload(parsed) };
}

async function putGithubSessionsFile(settings, bodyObj, shaOrNull) {
  const { token, owner, repo, branch, path } = settings;
  const pathSeg = path
    .split("/")
    .map((p) => encodeURIComponent(p))
    .join("/");
  const apiPath =
    "/repos/" +
    encodeURIComponent(owner) +
    "/" +
    encodeURIComponent(repo) +
    "/contents/" +
    pathSeg;
  const content = utf8ToBase64(JSON.stringify(bodyObj, null, 2));
  const payload = {
    message: "DonkeyCode: sync sessions",
    content,
    branch,
  };
  if (shaOrNull) payload.sha = shaOrNull;
  await githubApiRequest(
    apiPath,
    {
      method: "PUT",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(payload),
    },
    token
  );
}

